  const textNodes = [];
  buttons.forEach(b => textNodes.push(b.textContent?.trim()));

  // Get the heading text
  const heading = rightPanel.querySelector('[style*="margin: 10px 0"]');
  const headingText = heading ? heading.textContent?.trim() : 'no heading found';

  // Button states
  const btnStyles = [];
  buttons.forEach(b => {
    btnStyles.push({
      text: b.textContent?.trim(),
      cursor: b.style.cursor,
      opacity: b.style.opacity,
      background: b.style.background,
    });
  });

  console.log('Heading:', headingText);
  console.log('Buttons:', JSON.stringify(btnStyles));
  console.log('Button count:', buttons.length);
}
